  1→import {
  2→  Box,
  3→  CardPoints,
  4→  Icon,
  5→  ListCardTransition,
  6→  LoadingFooter,
  7→  SearchUsed,
  8→  SeparatorHorizontal,
  9→  Tabs,
 10→  Text,
 11→} from '@semparar/design-system-app';
 12→import theme from '@semparar/design-system-app/src/styles/theme';
 13→import React, { FC } from 'react';
 14→import { RefreshControl } from 'react-native';
 15→import ApiError from '../../atomic/organisms/ApiError';
 16→import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
 17→import PointsInfoBottomSheet from '../../atomic/organisms/PointsInfoBottomSheet';
 18→import BasicScreen from '../../atomic/templates/BasicScreen';
 19→import { getPlaceholder, useExtractRewardProgramScreen } from './index';
 20→import type {
 21→  EmptyListProps,
 22→  ExtractRewardProgramProps,
 23→  TransactionsListProps,
 24→} from './Models';
 25→
 26→const EmptyList = React.memo<EmptyListProps>(({ label }) => (
 27→  <Box width="100%" justify="center" align="center">
 28→    <Icon
 29→      name="icon-invoice-error"
 30→      size="lg"
 31→      color="INTENSE_COLOR_02"
 32→      mt="meddium"
 33→    />
 34→    <Text
 35→      type="paragraphLG"
 36→      pd="innerGreat"
 37→      color="INTENSE_COLOR_03"
 38→      align="center"
 39→    >
 40→      {label}
 41→    </Text>
 42→  </Box>
 43→));
 44→
 45→EmptyList.displayName = 'EmptyList';
 46→
 47→const TransactionsList = React.memo<TransactionsListProps>(({
 48→  items,
 49→  isLoading,
 50→}) => (
 51→  <ListCardTransition
 52→    items={items}
 53→    isLoading={isLoading}
 54→    scrollEnabled={false}
 55→    mb="meddium"
 56→  />
 57→));
 58→
 59→TransactionsList.displayName = 'TransactionsList';
 60→
 61→const LoadingMore = React.memo(() => (
 62→  <Box width="100%" align="center" justify="center" mt="small" mb="small">
 63→    <LoadingFooter />
 64→  </Box>
 65→));
 66→
 67→LoadingMore.displayName = 'LoadingMore';
 68→
 69→const ExtractRewardProgram: FC<ExtractRewardProgramProps> = ({
 70→  route,
 71→  navigation,
 72→}) => {
 73→  const {
 74→    hasError,
 75→    handleGoBack,
 76→    pointsAvailable,
 77→    isLoadingExtract,
 78→    isLoadingMore,
 79→    isLoadingBalance,
 80→    isRefreshing,
 81→    transactionsData,
 82→    searchText,
 83→    activeFiltersCount,
 84→    transactionsEmptyMessage,
 85→    shouldShowTransactionsList,
 86→    filterGroups,
 87→    initialFilters,
 88→    modalizeRefInfo,
 89→    modalizeRefFilters,
 90→    handleSearchChange,
 91→    handleRefresh,
 92→    handleError,
 93→    handleScroll,
 94→    handleIconInfoPress,
 95→    handleFilterIconPress,
 96→    handleApplyFilters,
 97→    handleTabChange,
 98→    handleSearchPressIn,
 99→  } = useExtractRewardProgramScreen({
100→    route,
101→    navigation,
102→  });
103→
104→  if (hasError) {
105→    return (
106→      <ApiError
107→        title="Algo deu errado!"
108→        subTitle="Por favor, tente de novo."
109→        isLoading={isLoadingExtract}
110→        onPress={handleError}
111→      />
112→    );
113→  }
114→
115→  return (
116→    <>
117→      <BasicScreen
118→        errorButtonOnPress={handleError}
119→        leftIconOnPress={handleGoBack}
120→        title="Extrato"
121→        hasScroll
122→        scrollViewProps={{
123→          refreshControl: (
124→            <RefreshControl
125→              onRefresh={handleRefresh}
126→              refreshing={isRefreshing}
127→              tintColor={theme.colors.BRAND_BASE_01}
128→            />
129→          ),
130→          onScroll: handleScroll,
131→          scrollEventThrottle: 16,
132→        }}
133→      >
134→        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
135→          <CardPoints
136→            icon="icon-benefits"
137→            iconInfo="icon-help"
138→            title="Pontos disponíveis"
139→            valuePoints={
140→              pointsAvailable
141→                ? Math.floor(pointsAvailable).toLocaleString('pt-br')
142→                : '0'
143→            }
144→            hideBottom
145→            isLoading={isLoadingBalance}
146→            onPressIconInfo={handleIconInfoPress}
147→          />
148→
149→          <Text
150→            type="paragraphXXXL"
151→            mb="xxxxs"
152→            mt="xxs"
153→            color="INTENSE_COLOR_05"
154→          >
155→            Lançamentos
156→          </Text>
157→
158→          <SeparatorHorizontal
159→            borderWidth="smaller"
160→            borderColor="BRAND_COMPLEMENT_02"
161→            height={1}
162→            mb="xxxxs"
163→            width="100%"
164→          />
165→          <SearchUsed
166→            placeholder={getPlaceholder()}
167→            onChangeText={handleSearchChange}
168→            value={searchText}
169→            showIcon={!!activeFiltersCount}
170→            firstIcon={undefined}
171→            onPressIn={handleSearchPressIn}
172→            numberIcon={activeFiltersCount}
173→            secondIcon="icon-filter-settings"
174→            secondOnPress={handleFilterIconPress}
175→            showFilter
176→          />
177→        </Box>
178→
179→        <Box
180→          ml={isLoadingExtract ? 'xs' : 'none'}
181→          mr={isLoadingExtract ? 'xs' : 'none'}
182→        >
183→          <Tabs
184→            items={[
185→              {
186→                id: 0,
187→                title: 'Todos',
188→                component: (
189→                  <TransactionsList
190→                    items={transactionsData}
191→                    isLoading={isLoadingExtract}
192→                  />
193→                ),
194→              },
195→              {
196→                id: 1,
197→                title: 'A expirar',
198→                component: <></>,
199→              },
200→            ]}
201→            showBackground={false}
202→            hasScroll={false}
203→            loadingType="light"
204→            onChange={handleTabChange}
205→            type="options"
206→            isLoading={isLoadingExtract}
207→          />
208→          {!shouldShowTransactionsList && (
209→            <EmptyList label={transactionsEmptyMessage} />
210→          )}
211→          {isLoadingMore && <LoadingMore />}
212→        </Box>
213→      </BasicScreen>
214→      <PointsInfoBottomSheet modalizeRef={modalizeRefInfo} />
215→      {filterGroups.length > 0 && (
216→        <FiltersBottomSheet
217→          modalizeRef={modalizeRefFilters}
218→          filterGroups={filterGroups}
219→          onApplyFilters={handleApplyFilters}
220→          initialFilters={initialFilters}
221→        />
222→      )}
223→    </>
224→  );
225→};
226→
227→export default ExtractRewardProgram;
