 29→export function getFilteredTransactions(
 30→  transactions: PointsTransaction[],
 31→  filters?: AppliedFilters,
 32→): PointsTransaction[] {
 33→  const hasFilters =
 34→    filters &&
 35→    (filters.period ||
 36→      (filters.types && filters.types.length > 0) ||
 37→      filters.order);
 38→
 39→  if (!hasFilters) {
 40→    return transactions;
 41→  }
 42→
 43→  const now = new Date();
 44→  const todayEnd = new Date(now);
 45→  todayEnd.setHours(23, 59, 59, 999);
 46→
 47→  const periodStart = filters.period
 48→    ? (() => {
 49→        const date = new Date(now);
 50→        date.setDate(date.getDate() - filters.period);
 51→        date.setHours(0, 0, 0, 0);
 52→        return date;
 53→      })()
 54→    : null;
 55→
 56→  const hasTypeFilter = filters.types && filters.types.length > 0;
 57→  const typesSet = hasTypeFilter
 58→    ? new Set(filters.types!.map(type => type.toUpperCase()))
 59→    : null;
 60→
 61→  const filtered = transactions.filter(transaction => {
 62→    const transactionDate = new Date(transaction.date);
 63→
 64→    if (!matchesPeriodFilter(transactionDate, periodStart, todayEnd)) {
 65→      return false;
 66→    }
 67→
 68→    if (!matchesTypeFilter(transaction.type, typesSet)) {
 69→      return false;
 70→    }
 71→
 72→    return true;
 73→  });
 74→
 75→  if (filters.order === 'DESC') {
 76→    return [...filtered].reverse();
 77→  }
 78→
 79→  return filtered;
 80→}
