109→export function getFilteredTransactionsByText(
110→  transactions: PointsTransaction[],
111→  searchText: string,
112→  isExpiringTab = false,
113→): PointsTransaction[] {
114→  if (!searchText?.trim() || !transactions?.length) {
115→    return transactions;
116→  }
117→
118→  const normalizedSearch = searchText.toLowerCase().trim();
119→
120→  return transactions.filter(transaction =>
121→    matchesSearchText(transaction, normalizedSearch, isExpiringTab));
122→}
